"use client";

import React, { useEffect, useState } from "react";
import Link from "next/link";
import { useAuthStore } from "@/store/auth.store";
import { ShoppingCart, Heart, LogOut, Menu, X, User } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";
import { usePathname } from "next/navigation";

export function Navbar() {
  const { user, token, logout, initialize } = useAuthStore();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const pathname = usePathname();

  useEffect(() => {
    initialize();
  }, [initialize]);

  const navLinks = [
    { name: "Home", href: "/" },
    { name: "Products", href: "/products" },
    { name: "Categories", href: "/categories" },
    { name: "Brands", href: "/brands" },
  ];

  const handleLogout = () => {
    logout();
    window.location.href = "/login";
  };

  return (
    <nav className="sticky top-0 z-50 w-full bg-white/80 dark:bg-slate-950/80 backdrop-blur-lg border-b border-slate-200 dark:border-slate-800 transition-colors duration-300">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-16">
          {/* Logo */}
          <div className="flex-shrink-0 flex items-center">
            <Link href="/" className="flex items-center gap-2">
              <ShoppingCart className="h-8 w-8 text-orange-600" />
              <span className="font-extrabold text-2xl tracking-tight text-slate-900 dark:text-white">
                Shop<span className="text-orange-600">Mart</span>
              </span>
            </Link>
          </div>

          {/* Desktop Navigation */}
          {token && (
            <div className="hidden md:flex space-x-8 items-center">
              {navLinks.map((link) => (
                <Link
                  key={link.name}
                  href={link.href}
                  className={cn(
                    "text-sm font-medium transition-colors hover:text-orange-600",
                    pathname === link.href 
                      ? "text-orange-600 font-semibold" 
                      : "text-slate-600 dark:text-slate-300"
                  )}
                >
                  {link.name}
                </Link>
              ))}
            </div>
          )}

          {/* User Actions */}
          <div className="hidden md:flex items-center space-x-6">
            {!token ? (
              <div className="flex items-center gap-4">
                <Link href="/login" className="text-sm font-medium text-slate-700 dark:text-slate-300 hover:text-orange-600">
                  Login
                </Link>
                <Link href="/register" className="text-sm font-medium bg-orange-600 text-white px-4 py-2 rounded-md hover:bg-orange-700 transition">
                  Sign Up
                </Link>
              </div>
            ) : (
              <div className="flex items-center gap-5">
                <Link href="/wishlist" className="relative text-slate-600 dark:text-slate-300 hover:text-orange-600 transition">
                  <Heart className="h-6 w-6" />
                </Link>
                <Link href="/cart" className="relative text-slate-600 dark:text-slate-300 hover:text-orange-600 transition">
                  <ShoppingCart className="h-6 w-6" />
                </Link>
                <div className="h-6 w-px bg-slate-300 dark:bg-slate-700" />
                <div className="group relative flex items-center gap-2 cursor-pointer text-slate-600 dark:text-slate-300 hover:text-orange-600 transition">
                  <div className="h-8 w-8 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center border border-slate-200 dark:border-slate-700">
                    <User className="h-4 w-4" />
                  </div>
                  <span className="text-sm font-medium capitalize max-w-[100px] truncate">{user?.name}</span>
                  
                  {/* Dropdown */}
                  <div className="absolute top-full right-0 mt-2 w-48 bg-white dark:bg-slate-900 rounded-md shadow-lg border border-slate-200 dark:border-slate-800 opacity-0 invisible group-hover:opacity-100 group-hover:visible transition-all duration-200 origin-top-right">
                    <div className="py-1">
                      <button 
                        onClick={handleLogout}
                        className="w-full flex items-center gap-2 px-4 py-2 text-sm text-red-600 hover:bg-red-50 dark:hover:bg-red-500/10"
                      >
                        <LogOut className="h-4 w-4" />
                        Sign Out
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Mobile menu button */}
          <div className="flex md:hidden items-center">
            <button
              onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
              className="text-slate-600 dark:text-slate-300 hover:text-orange-600"
            >
              {isMobileMenuOpen ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      <AnimatePresence>
        {isMobileMenuOpen && (
          <motion.div
            initial={{ height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={{ height: 0, opacity: 0 }}
            className="md:hidden overflow-hidden bg-white dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800"
          >
            <div className="px-4 py-4 justify-between flex flex-col gap-4">
              {token ? (
                <>
                  <div className="flex flex-col gap-2">
                    {navLinks.map((link) => (
                      <Link
                        key={link.name}
                        href={link.href}
                        onClick={() => setIsMobileMenuOpen(false)}
                        className={cn(
                          "px-3 py-2 rounded-md text-base font-medium",
                          pathname === link.href ? "bg-orange-50 dark:bg-orange-500/10 text-orange-600" : "text-slate-700 dark:text-slate-300"
                        )}
                      >
                        {link.name}
                      </Link>
                    ))}
                  </div>
                  <div className="border-t border-slate-200 dark:border-slate-800 pt-4 flex flex-col gap-3">
                    <Link href="/wishlist" className="flex items-center gap-3 px-3 py-2 text-slate-700 dark:text-slate-300">
                      <Heart className="h-5 w-5" /> Wishlist
                    </Link>
                    <Link href="/cart" className="flex items-center gap-3 px-3 py-2 text-slate-700 dark:text-slate-300">
                      <ShoppingCart className="h-5 w-5" /> Cart
                    </Link>
                    <button onClick={handleLogout} className="flex items-center gap-3 px-3 py-2 text-red-600">
                      <LogOut className="h-5 w-5" /> Sign Out
                    </button>
                  </div>
                </>
              ) : (
                <div className="flex flex-col gap-3 px-3">
                  <Link href="/login" onClick={() => setIsMobileMenuOpen(false)} className="text-slate-700 dark:text-slate-300 font-medium py-2">
                    Login
                  </Link>
                  <Link href="/register" onClick={() => setIsMobileMenuOpen(false)} className="bg-orange-600 text-white text-center rounded-md py-2 font-medium">
                    Sign Up
                  </Link>
                </div>
              )}
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </nav>
  );
}
